import{_ as a,o,c as e,ae as r}from"./chunks/framework.C8MNLDzb.js";const q=JSON.parse('{"title":"《庄子·逍遥游》节选","description":"","frontmatter":{},"headers":[],"relativePath":"zi/逍遥游.md","filePath":"zi/逍遥游.md"}'),d={name:"zi/逍遥游.md"};function n(h,t,l,i,s,u){return o(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="《庄子·逍遥游》节选" tabindex="-1">《庄子·逍遥游》节选 <a class="header-anchor" href="#《庄子·逍遥游》节选" aria-label="Permalink to &quot;《庄子·逍遥游》节选&quot;">​</a></h1><hr><h2 id="原文" tabindex="-1">原文 <a class="header-anchor" href="#原文" aria-label="Permalink to &quot;原文&quot;">​</a></h2><blockquote><p>北冥有鱼，其名为鲲。鲲之大，不知其几千里也。化而为鸟，其名为鹏。鹏之背，不知其几千里也。怒而飞，其翼若垂天之云。是鸟也，海运则将徙于南冥。南冥者，天池也。</p></blockquote><blockquote><p>《齐谐》者，志怪者也。《谐》之言曰：&quot;鹏之徙于南冥也，水击三千里，抟扶摇而上者九万里，去以六月息者也。&quot;野马也，尘埃也，生物之以息相吹也。天之苍苍，其正色邪？其远而无所至极邪？其视下也，亦若是则已矣。</p></blockquote><hr><h2 id="题解" tabindex="-1">题解 <a class="header-anchor" href="#题解" aria-label="Permalink to &quot;题解&quot;">​</a></h2><p>《逍遥游》是《庄子》的首篇，也是其哲学思想的核心代表。</p><p><strong>逍遥</strong> — 形容无所拘束、自由自在的精神境界。</p><p><strong>鲲鹏</strong> — 庄子想象中的巨大生物，鲲化为鹏，象征精神的超脱与升华。</p><hr><h2 id="核心思想" tabindex="-1">核心思想 <a class="header-anchor" href="#核心思想" aria-label="Permalink to &quot;核心思想&quot;">​</a></h2><h3 id="无待之境" tabindex="-1">无待之境 <a class="header-anchor" href="#无待之境" aria-label="Permalink to &quot;无待之境&quot;">​</a></h3><p>庄子认为，真正的自由不在于改变外在环境，而在于超越对外在条件的依赖，达到&quot;无己、无功、无名&quot;的境界。</p><h3 id="大小之辨" tabindex="-1">大小之辨 <a class="header-anchor" href="#大小之辨" aria-label="Permalink to &quot;大小之辨&quot;">​</a></h3><table tabindex="0"><thead><tr><th>层次</th><th>境界</th></tr></thead><tbody><tr><td>蜩与学鸠</td><td>&quot;之二虫又何知&quot;，小知不及大知</td></tr><tr><td>彭祖</td><td>寿而有待，未能逍遥</td></tr><tr><td>列子</td><td>御风而行，犹有所待</td></tr><tr><td>至人</td><td>无己、无功、无名，乘天地之正</td></tr></tbody></table><hr><h2 id="名句赏析" tabindex="-1">名句赏析 <a class="header-anchor" href="#名句赏析" aria-label="Permalink to &quot;名句赏析&quot;">​</a></h2><blockquote><p>&quot;鹏之徙于南冥也，水击三千里，抟扶摇而上者九万里&quot;</p></blockquote><p>大鹏展翅，扶摇直上，气象万千。后世用&quot;鹏程万里&quot;比喻前程远大。</p><hr><p><strong>分类：</strong> 子部 <strong>体裁：</strong> 典籍 <strong>时代：</strong> 先秦 <strong>标签：</strong> 庄子、道家、自由、逍遥游、哲学</p>',22)])])}const p=a(d,[["render",n]]);export{q as __pageData,p as default};
